// Pega o texto de entrada
const input = $input.first().json.output;

// ---------- 1) Limpa markdown e ruídos ----------
function cleanMarkdown(text) {
  return String(text || '')
    .replace(/```[\s\S]*?```/g, '')        // blocos de código
    .replace(/!\[.*?\]\(.*?\)/g, '')       // imagens markdown
    .replace(/\[(.*?)\]\(.*?\)/g, '$1')    // links markdown
    .replace(/[*_~`>#]+/g, '')             // ênfases, títulos etc.
    .replace(/\n{2,}/g, '\n\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
}

// ---------- 2) Quebra em frases SEM quebrar e-mail / URL / abreviações ----------
function splitBySentence(text) {
  const DOT = '∯';
  let safe = String(text || '');

  // Proteções (mantém as mesmas)
  safe = safe.replace(/\bhttps?:\/\/[^\s]+/gi, m => m.replace(/\./g, DOT));
  safe = safe.replace(/\bwww\.[^\s]+/gi, m => m.replace(/\./g, DOT));
  safe = safe.replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, m => m.replace(/\./g, DOT));

  // Domínios soltos (ex: exemplo.com.br) — cuidado pra não pegar frases normais
  safe = safe.replace(/\b[a-z0-9-]+(?:\.[a-z0-9-]+){1,}\b/gi, m => m.replace(/\./g, DOT));

  // Abreviações comuns (endereços/títulos) — você pode expandir aqui
  safe = safe.replace(/\b(R|Av|Al|Rod|Rua|Dr|Dra|Sr|Sra|Prof|Profa|Eng|Nº|No|Conj|Bl|Bloco|Apto|Ap)\./gi, `$1${DOT}`);

  const result = [];
  let current = '';

  const len = safe.length;
  for (let i = 0; i < len; i++) {
    const ch = safe[i];
    current += ch;

    if (ch === '!' || ch === '?') {
      let trimmed = current.replace(/\s+/g, ' ').trim();
      if (trimmed) result.push(trimmed.replaceAll(DOT, '.'));
      current = '';
      continue;
    }

    if (ch === '.') {
      const prev = safe[i - 1] || '';
      const next = safe[i + 1] || '';

      // não corta em número decimal / milhar
      if (/\d/.test(prev) && /\d/.test(next)) continue;

      // REGRA NOVA:
      // só considera fim de frase se após o ponto vier:
      // - espaço + letra maiúscula (nova frase)
      // - ou quebra de linha
      // - ou fim do texto
      const lookahead = safe.slice(i + 1, i + 4); // pega próximos chars
      const isEnd = i === len - 1;
      const isNewline = next === '\n' || next === '\r';
      const isSpaceThenUpper = lookahead.length >= 2 && /^\s[A-ZÁÉÍÓÚÂÊÔÃÕÇ]/.test(lookahead);

      if (!isEnd && !isNewline && !isSpaceThenUpper) {
        // ponto no meio (ex: "Conj.", "Bloco O.", siglas, etc.) -> não quebra
        continue;
      }

      let trimmed = current.replace(/\s+/g, ' ').trim();
      if (trimmed) result.push(trimmed.replaceAll(DOT, '.'));
      current = '';
    }
  }

  let rest = current.replace(/\s+/g, ' ').trim();
  if (rest) result.push(rest.replaceAll(DOT, '.'));

  return result;
}

// ---------- 3) Conversão de números para extenso (para FULL_ANSWER) ----------
const UNIDADES = ['zero','um','dois','três','quatro','cinco','seis','sete','oito','nove'];
const DEZ_A_DEZENOVE = ['dez','onze','doze','treze','quatorze','quinze','dezesseis','dezessete','dezoito','dezenove'];
const DEZENAS = ['','dez','vinte','trinta','quarenta','cinquenta','sessenta','setenta','oitenta','noventa'];
const CENTENAS = ['','cem','duzentos','trezentos','quatrocentos','quinhentos','seiscentos','setecentos','oitocentos','novecentos'];
const ESC_SING = ['','mil','milhão','bilhão','trilhão'];
const ESC_PLUR = ['','mil','milhões','bilhões','trilhões'];

function centenaExt(n){
  if (n === 0) return '';
  if (n === 100) return 'cem';
  const c = Math.floor(n/100), d = Math.floor((n%100)/10), u = n%10;
  const out = [];
  if (c > 0) out.push(c === 1 ? 'cento' : CENTENAS[c]);
  if (d === 1) out.push(DEZ_A_DEZENOVE[u]);
  else {
    if (d > 0) out.push(DEZENAS[d]);
    if (u > 0) out.push(UNIDADES[u]);
  }
  return out.join(' e ');
}

function inteiroExt(n){
  if (n === 0) return 'zero';
  if (n < 0) return 'menos ' + inteiroExt(Math.abs(n));
  const grupos = []; let i = 0;
  while (n > 0 && i <= 4) {
    const g = n % 1000;
    if (g > 0) {
      let t = centenaExt(g);
      if (i > 0) {
        const esc = (g === 1) ? ESC_SING[i] : ESC_PLUR[i];
        if (i === 1 && g === 1) t = 'mil';
        else if (esc) t += ' ' + esc;
      }
      grupos.unshift(t);
    }
    n = Math.floor(n / 1000);
    i++;
  }
  return grupos.join(', ').replace(/, ([^,]+)$/, ' e $1');
}

function numerosParaExtenso(texto){
  let t = String(texto || '');
  t = t.replace(/R\$\s*/g, '');

  t = t.replace(/\b\d{1,3}(?:\.\d{3})*\b(?![\d%])/g, (m) => {
    const digits = m.replace(/\./g, '');
    if (!digits.length || digits.length > 6) return m;
    const n = parseInt(digits, 10);
    return isFinite(n) ? inteiroExt(n) : m;
  });

  return t;
}

// ---------- 4) Processamento ----------
const cleaned = cleanMarkdown(String(input || ''));

const messages = splitBySentence(cleaned);
const full_answer = numerosParaExtenso(cleaned);

// ---------- 5) Retorno ----------
return [
  {
    json: {
      output: {
        messages,
        full_answer,
      },
    },
  },
];
